 namespace WPAICG\AutoGPT\Ajax\Actions\RunNow; use WPAICG\AutoGPT\Ajax\AIPKit_Run_Automated_Task_Now_Action; use WPAICG\AutoGPT\Helpers; use WP_Error; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Content_Queuer; use WPAICG\AutoGPT\Cron\EventProcessor\Trigger\Modules as ContentWritingModules; use WPAICG\AutoGPT\Cron\EventProcessor\Trigger; use WPAICG\AutoGPT\Cron\AIPKit_Automated_Task_Event_Processor; if (!defined('ABSPATH')) { exit; } require_once WPAICG_PLUGIN_DIR . 'classes/autogpt/helpers/task-type-access.php'; function validate_task_and_permissions_logic(AIPKit_Run_Automated_Task_Now_Action $handler): array|WP_Error { $permission_check = $handler->check_module_access_permissions('autogpt', $handler::NONCE_ACTION); if (is_wp_error($permission_check)) { return $permission_check; } $task_id = isset($_POST['task_id']) ? absint($_POST['task_id']) : 0; if (empty($task_id)) { return new WP_Error('missing_task_id_run_now', __('Task ID is required.', 'gpt3-ai-content-generator'), ['status' => 400]); } global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $task = $wpdb->get_row($wpdb->prepare("SELECT * FROM {$tasks_table_name} WHERE id = %d", $task_id), ARRAY_A); if (!$task) { return new WP_Error('task_not_found_run', __('Task not found.', 'gpt3-ai-content-generator'), ['status' => 404]); } if ($task['status'] !== 'active') { return new WP_Error('task_not_active_run', __('Task must be active to run now.', 'gpt3-ai-content-generator'), ['status' => 400]); } if (Helpers\task_type_requires_pro_plan((string) ($task['task_type'] ?? '')) && !Helpers\is_pro_plan_active()) { return new WP_Error('task_type_requires_pro_plan_run_now', __('This is a Pro feature.', 'gpt3-ai-content-generator'), ['status' => 403]); } return $task; } function run_now_content_indexing_logic(int $task_id, array $task_config): void { if (class_exists(AIPKit_Automated_Task_Content_Queuer::class)) { AIPKit_Automated_Task_Content_Queuer::maybe_queue_initial_indexing_content($task_id, $task_config, true); } } namespace WPAICG\AutoGPT\Ajax\Actions\RunNow; $modules_path = WPAICG_PLUGIN_DIR . 'classes/autogpt/cron/event-processor/trigger/module/'; require_once $modules_path . 'methods.php'; if (!defined('ABSPATH')) { exit; } function run_now_content_writing_logic(int $task_id, array $task_config): bool|WP_Error { $generation_mode = $task_config['cw_generation_mode'] ?? 'single'; $topics_to_queue = []; $scraped_contexts = []; switch ($generation_mode) { case 'rss': $topics_to_queue = ContentWritingModules\rss_mode_generate_items_logic($task_id, $task_config, null); break; case 'gsheets': $topics_to_queue = ContentWritingModules\gsheets_mode_generate_items_logic($task_id, $task_config); break; case 'url': $result = ContentWritingModules\url_mode_generate_items_logic($task_id, $task_config); if (!is_wp_error($result)) { $topics_to_queue = $result['topics']; $scraped_contexts = $result['contexts']; } else { $topics_to_queue = $result; } break; default: $topics_to_queue = ContentWritingModules\manual_mode_generate_items_logic($task_config); break; } if (is_wp_error($topics_to_queue)) { return $topics_to_queue; } if (empty($topics_to_queue)) { return new WP_Error('no_titles_to_queue', __('No new or valid items found in the source to generate content for.', 'gpt3-ai-content-generator'), ['status' => 400]); } $queued_count = 0; $item_index = 0; foreach ($topics_to_queue as $index => $item_data) { $item_config = ContentWritingModules\prepare_item_config_logic($item_data, $task_config, $scraped_contexts); if (empty($item_config['content_title'])) { continue; } $scheduled_gmt_time = ContentWritingModules\compute_item_schedule_gmt_logic($item_data, $task_config, $item_index, $generation_mode); if ($scheduled_gmt_time) { $item_config['scheduled_gmt_time'] = $scheduled_gmt_time; } $target_identifier = ContentWritingModules\generate_target_identifier_logic($item_data, $task_id, $index); if ($generation_mode !== 'bulk' && $generation_mode !== 'csv' && $generation_mode !== 'single') { if (ContentWritingModules\is_duplicate_topic_logic($task_id, $target_identifier)) { continue; } } if (ContentWritingModules\insert_topic_into_queue_logic($task_id, $target_identifier, $item_config)) { $queued_count++; $item_index++; } } return true; } function run_now_comment_reply_logic(int $task_id, array $task_config, ?string $last_run_time): void { if (function_exists('\WPAICG\AutoGPT\Cron\EventProcessor\Trigger\trigger_comment_reply_task_logic')) { Trigger\trigger_comment_reply_task_logic($task_id, $task_config, null); } } function run_now_content_enhancement_logic(int $task_id, array $task_config): void { if (function_exists('\WPAICG\AutoGPT\Cron\EventProcessor\Trigger\trigger_content_enhancement_task_logic')) { Trigger\trigger_content_enhancement_task_logic($task_id, $task_config, null); } } function finalize_run_now_task_logic(int $task_id): void { global $wpdb; $tasks_table_name = $wpdb->prefix . 'aipkit_automated_tasks'; $wpdb->update( $tasks_table_name, ['last_run_time' => current_time('mysql', 1)], ['id' => $task_id], ['%s'], ['%d'] ); if (class_exists(AIPKit_Automated_Task_Event_Processor::class)) { wp_schedule_single_event(time() + 5, AIPKit_Automated_Task_Event_Processor::MAIN_CRON_HOOK); } } 